// inferred-not-tested:PixiJS v8 必须先 new Application 再 await init
import { Application, Graphics } from 'https://cdn.jsdelivr.net/npm/pixi.js@8/+esm';
const el = document.getElementById('pixi'); el.style.height = '400px';
const app = new Application(); await app.init({ resizeTo: el, background: data.background ?? '#0b1020', antialias: data.antialias ?? true });
app.canvas.style.display = 'block'; el.appendChild(app.canvas);
for (const s of data.shapes) { const g = new Graphics(); if (s.type === 'circle') g.circle(s.x, s.y, s.radius ?? 40); else g.rect(s.x, s.y, s.width ?? 80, s.height ?? 80); g.fill({ color: s.fill, alpha: s.alpha ?? 1 }); app.stage.addChild(g); }

